// Entire CLI plugin for OpenCode
// Auto-generated by `entire enable --agent opencode`
// Do not edit manually — changes will be overwritten on next install.
// Requires Bun runtime (used by OpenCode's plugin system for loading ESM plugins).
import type { Plugin } from "@opencode-ai/plugin"
/**
 * Spawns a detached child process that calls `entire hooks opencode session-end`
 * for any tracked sessions when the parent process dies unexpectedly (e.g. os.Exit).
 *
 * The child stays alive via a stdin pipe. The parent sends track/untrack messages.
 * When the parent dies, the pipe closes (EOF), and the child runs cleanup.
 */
function spawnSessionCleanupWatcher() {
  const child = Bun.spawn(["node", "-e", `
    const { execSync } = require("child_process");
    const sessions = new Set();
    let buf = "";
    process.stdin.on("data", (chunk) => {
      buf += chunk;
      let nl;
      while ((nl = buf.indexOf("\\n")) !== -1) {
        const line = buf.slice(0, nl);
        buf = buf.slice(nl + 1);
        try {
          const msg = JSON.parse(line);
          if (msg.type === "track") sessions.add(msg.session_id);
          if (msg.type === "untrack") sessions.delete(msg.session_id);
        } catch {}
      }
    });
    process.stdin.on("end", () => {
      for (const sid of sessions) {
        try {
          execSync(\`echo \${JSON.stringify(JSON.stringify({ session_id: sid }))} | entire hooks opencode session-end\`);
        } catch {}
      }

